"use strict";(function(){let logged_in=false;let currentUserId=null;let p_input,u_input,new_p_input,new_u_input,new_site_input;let app,add_Button,submit_Button;const validateUserCredentials=function(){const username=u_input.field.value.trim();const password=p_input.field.value.trim();fetch("/api/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:username,master_password:password})}).then(res=>res.json()).then(data=>{if(data.success){logged_in=true;currentUserId=data.userId;console.log(`user${username} has been logged in`);retrievePasswords(currentUserId);new_p_input.setup(200,30,"","Enter Password...");new_u_input.setup(200,30,"","Enter Username...");new_site_input.setup(200,30,"","Enter Website...");if(new_site_input.elem){new_site_input.build(app)}if(new_u_input.elem){new_u_input.build(app)}if(new_p_input.elem){new_p_input.build(app)}if(!document.body.contains(add_Button)){app.appendChild(add_Button)}}})};const retrievePasswords=function(userId){const username=u_input.elem.value;fetch(`/api/user/passwords/all/${userId}`,{method:"GET",headers:{"Content-Type":"application/json"}}).then(res=>res.json()).then(rows=>{if(Array.isArray(rows)){console.log(`Retrieved data of ${username}`);const container=document.getElementById("userFieldsContainer");container.innerHTML="";rows.forEach(entry=>{const row=document.createElement("div");row.className="entry-row";Object.create(DisplayField).setup(100,30,"Site",entry.site).build(row);Object.create(DisplayField).setup(100,30,"Password",entry.password).build(row);container.appendChild(row)})}})};const addNewPassword=function(){const username=new_u_input.field.value;const site=new_site_input.field.value;const password=new_p_input.field.value;if(!username||!password||!site){return}fetch("/api/user/passwords",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({userId:currentUserId,site:site,username:username,password:password})}).then(res=>res.json()).then(data=>{if(data.success){console.log(`Password ${password} to site ${site} for user ${username} has been added`);retrievePasswords(currentUserId)}})};const init=function(){app=document.querySelector("#app")||document.body;app.classList.add("center");app.classList.add("stack");app.style.setProperty("--space","var(--s1)");p_input=Object.create(InputField);u_input=Object.create(InputField);new_p_input=Object.create(InputField);new_u_input=Object.create(InputField);new_site_input=Object.create(InputField);u_input.setup(200,30,"Enter Username...","Enter Username...");u_input.build(app);p_input.setup(200,30,"Enter Password...","Enter Password...");p_input.build(app);add_Button=document.createElement("button");add_Button.textContent="Submit New Password Pair";add_Button.classList.add("button");submit_Button=document.createElement("button");submit_Button.textContent="Login";submit_Button.classList.add("button");app.appendChild(submit_Button);if(!document.getElementById("userFieldsContainer")){const container=document.createElement("div");container.id="userFieldsContainer";app.appendChild(container)}submit_Button.addEventListener("click",function(event){validateUserCredentials()});add_Button.addEventListener("click",function(event){addNewPassword()})};if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init)}else{init()}})();